"""Class-based runtime-хранилище и фасад для AppConfig."""from __future__ import annotationsfrom pathlib import Pathfrom .app_config import AppConfigclass AppConfigStore:    """Единая class-based точка доступа к runtime-конфигу и app.ini."""    _current: AppConfig | None = None    @classmethod    def get(cls) -> AppConfig:        """Возвращает текущий активный конфиг. Если не установлен — AppConfig.default()."""        if cls._current is None:            return AppConfig.default()        return cls._current    @classmethod    def set(cls, config: AppConfig | None) -> None:        """Устанавливает текущий активный конфиг. None эквивалентен сбросу."""        cls._current = config    @classmethod    def reset(cls) -> None:        """Сбрасывает текущий конфиг. После reset() get() возвращает AppConfig.default()."""        cls._current = None    @classmethod    def load_or_create(cls, root: Path | None = None) -> AppConfig:        """Загружает или создаёт app.ini, обновляет runtime-store и возвращает AppConfig."""        from .app_config_builder import load_or_create as _builder_load_or_create        config = _builder_load_or_create(root)        cls.set(config)        return config    @classmethod    def save(cls, config: AppConfig, root: Path | None = None) -> None:        """Сохраняет app.ini и синхронизирует runtime-store."""        from .app_config_builder import save_config as _builder_save_config        _builder_save_config(config, root)        cls.set(config)